package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertSame;
import static org.mockito.Mockito.mock;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSetFieldNamingPolicy_withValidPolicy_shouldSetFieldNamingPolicy() throws Exception {
    FieldNamingPolicy policy = FieldNamingPolicy.LOWER_CASE_WITH_DASHES;

    GsonBuilder returned = gsonBuilder.setFieldNamingPolicy(policy);

    assertSame(gsonBuilder, returned);

    // Using reflection to verify private field fieldNamingPolicy is set correctly
    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object actualPolicy = field.get(gsonBuilder);
    assertSame(policy, actualPolicy);
  }

  @Test
  public void testSetFieldNamingPolicy_withIdentityPolicy_shouldSetFieldNamingPolicy() throws Exception {
    FieldNamingPolicy policy = FieldNamingPolicy.IDENTITY;

    GsonBuilder returned = gsonBuilder.setFieldNamingPolicy(policy);

    assertSame(gsonBuilder, returned);

    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object actualPolicy = field.get(gsonBuilder);
    assertSame(policy, actualPolicy);
  }

  @Test
  public void testSetFieldNamingPolicy_withNull_shouldSetFieldNamingPolicyToNull() throws Exception {
    // According to GsonBuilder#setFieldNamingStrategy accepts null, so this should set to null
    GsonBuilder returned = gsonBuilder.setFieldNamingPolicy(null);

    assertSame(gsonBuilder, returned);

    Field field = GsonBuilder.class.getDeclaredField("fieldNamingPolicy");
    field.setAccessible(true);
    Object actualPolicy = field.get(gsonBuilder);
    // It should be null now
    org.junit.jupiter.api.Assertions.assertNull(actualPolicy);
  }
}
